import { createBrowserRouter, Navigate } from "react-router-dom";

import VerbTable from "../components/verb/VerbTable";
import WordList from "./components/word/WordList";

import Navbar from "../components/Navbar";
import QuoteBar from "../components/QuoteBar";
import { useAuth } from "../context/AuthContext";
import AuthPage from "./pages/AuthPage";
import DashboardPage from "./pages/DashboardPage";
import HomePage from "./pages/HomePage";
import LessonPage from "./pages/LessonPage";

/* ---------------- Layout ---------------- */
function Layout({ children }) {
  return (
    <div className="min-h-screen bg-[rgb(26_24_41/var(--tw-bg-opacity,1))]">
      <QuoteBar />
      <Navbar />
      <main className="py-2">{children}</main>
    </div>
  );
}

/* ---------------- Private Route ---------------- */
function PrivateRoute({ children }) {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="text-5xl animate-bounce mb-4">🗣️</div>
          <p className="text-slate-500 font-bold">Loading SpeakUp...</p>
        </div>
      </div>
    );
  }

  return user ? children : <Navigate to="/auth" />;
}

/* ---------------- Page Wrapper Helper ---------------- */
const withLayout = (element) => (
  <PrivateRoute>
    <Layout>{element}</Layout>
  </PrivateRoute>
);

/* ---------------- Router ---------------- */
export const router = createBrowserRouter([
  {
    path: "/auth",
    element: <AuthPage />,
  },
  {
    path: "/",
    element: withLayout(<HomePage />),
  },
  {
    path: "/lesson/:levelId/:day",
    element: withLayout(<LessonPage />),
  },
  {
    path: "/dashboard",
    element: withLayout(<DashboardPage />),
  },
  {
    path: "/verbs",
    element: withLayout(<VerbTable />),
  },
  {
    path: "/words",
    element: withLayout(<WordList />),
  },
  {
    path: "*",
    element: <Navigate to="/" />,
  },
]);
